#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll,ll>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5;
ll n, c, d[MAXN], k[MAXN],e;
vector<PII> Edge[MAXN];
void dfs(int u, int fa)
{
	for (int i = 0; i < Edge[u].size(); ++i)
	{
		int s = Edge[u][i].first;
		if (s == fa) continue;
		d[s] = d[u] + Edge[u][i].second;
		k[s] = k[u] + 1;
		if (d[s] > d[c]) c = s;
		dfs(s, u);
	}
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (int i = 1, u, v, d; i < n; ++i)
	{
		u = read(), v = read(), d = read();
		Edge[u].push_back(mk(v, d));
		Edge[v].push_back(mk(u, d));
	}
	dfs(1, -1);
	d[c] = 0;e=c;
	dfs(c, -1);
	write(d[c]);
	puts("");
	write(k[c]-k[e]-1);
	return false;
}
